function Footer() {
  return (
    <footer className="site-footer">
      <div className="panel section">
        <strong>CampusCycle</strong>
        <p className="muted">
          A campus reuse platform focused on lower waste, lower costs, and more thoughtful student handoffs.
        </p>
      </div>
    </footer>
  );
}

export default Footer;
